import json,sys,urllib.request,time
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def GET(w):
    for a in range(6):
        try: return json.load(urllib.request.urlopen(urllib.request.Request(B+w,headers={'X-N8N-API-KEY':K}),timeout=20))
        except Exception: time.sleep(3)
    return None
lst=GET('workflows?limit=250'); ws=lst.get('data') if isinstance(lst,dict) else lst
print('усього воркфлоу:',len(ws))
for w in ws:
    d=GET('workflows/'+w['id'])
    if not d: print(w.get('name'),'-> GET fail'); continue
    trigs=[]
    for n in d.get('nodes',[]):
        t=n.get('type',''); p=n.get('parameters',{}) or {}
        if t=='n8n-nodes-base.scheduleTrigger':
            rule=(p.get('rule') or {}).get('interval') or []
            for it in rule:
                f=it.get('field'); 
                if f=='seconds': trigs.append('КОЖНІ %s сек'%it.get('secondsInterval','?'))
                elif f=='minutes': trigs.append('КОЖНІ %s хв'%it.get('minutesInterval','?'))
                elif f=='hours': trigs.append('кожні %s год'%it.get('hoursInterval','?'))
                elif f=='days': trigs.append('щодня о %s:00'%it.get('triggerAtHour','?'))
                elif f=='cronExpression': trigs.append('cron: '+str(it.get('expression')))
                else: trigs.append('sched:'+str(f))
        elif t=='n8n-nodes-base.cron': trigs.append('cron-node')
        elif t=='n8n-nodes-base.interval': trigs.append('interval:'+str(p.get('interval')))
        elif t in ('n8n-nodes-base.emailReadImap','n8n-nodes-base.emailReadImapV2') or 'imap' in t.lower(): trigs.append('IMAP-пошта (постійний опит)')
        elif t=='n8n-nodes-base.webhook': trigs.append('webhook (за викликом)')
        elif 'Trigger' in t or 'trigger' in t: trigs.append('trigger:'+t.split('.')[-1])
    print(('[ON ] ' if w.get('active') else '[off] ')+w['id'][:8]+' | '+w.get('name','')+' -> '+(', '.join(trigs) if trigs else 'без тригера'))

PYEOF
